#define MAX_STEPS 100
#define MAX_DIST 100.
#define SURF_DIST .001
#define TAU 6.283185
#define PI 3.141592
#define S smoothstep
#define T iTime

uniform vec2 u_mouse;


// ANIMATION *************************************************************************************
// ROT
mat2 Rot(float a) {
    float s=sin(a), c=cos(a);
    return mat2(c, -s, s, c);
}


// FUNCTION *************************************************************************************
// PARABULA
float Parabula(vec3 p){
    return p.y-p.x*sqrt(25.-p.x)/5.;
}
// SMALL MINIMUM
float smin(float a,float b,float k){
    float h = clamp(.5+.5*(b-a)/k,.0,1.);
    return mix(b,a,h)-k*h*(1.-h);
}




// SHAPES *************************************************************************************
float Ball(vec3 p,float r){
    return length(p)-r;
}
float Box(vec3 p, vec3 s) {
    p = abs(p)-s;
	return length(max(p, 0.))+min(max(p.x, max(p.y, p.z)), 0.);
}
float Capsule(vec3 p ,vec3 a,vec3 b , vec2 raduis){
      vec3 ab = b - a;
    vec3 ap = p - a;

    float t = dot(ab, ap) / dot(ab, ab);
    t = clamp(t, 0.0, 1.0);
    vec3 c = a + t * ab;

    float r = mix(raduis.x, raduis.y, t); // Interpolate radius
    return length(p - c) - r;

}
// SCUPTING *************************************************************************************
float Tail(vec3 p){

    // TAIL SHAPE
    p.y/=0.2;
    float b1 = Ball(p-vec3(-2,.0,0.),0.8);
    p.y*=0.2;


    float b2 = Ball(p-vec3(-2.8,.0,0.),1.1);
    float t = max(b1,-b2)/5.;
    return t;
}
float Wing(vec3 p){
    vec3 pw = p;
    // pw.xz*=Rot(sin(.1));
    // pw.z = abs(pw.z)+1.;

    //UPPER
    vec2 wingUpperA = vec2(.9,-.3);
    vec2 wingUpperB = vec2(.6,-.7);
    //LOWER
    vec2 wingPosA = vec2(.5,-.8);
    vec2 wingPosB = vec2(0.,-1.2);
    // pw.z+=sin(-pw.y);
    float wur= Capsule(pw,vec3(vec2(wingUpperB),-.5),vec3(wingUpperA,0.),vec2(.15,.07));
    float wr= Capsule(pw,vec3(vec2(wingPosB),-.5),vec3(wingPosA,-0.5),vec2(.03,.15));
    wr =smin(wur,wr,.12);
    // pw.xz*=scale;
    // p.z+=sin(pw.y);
    float wl= Capsule(p,vec3(vec2(wingPosB),2.5),vec3(wingPosA,2.),vec2(.01,.15));
    float w = min(wr,wl);
   return w/2.;
}
float Body(vec3 p){
    vec3 ph = p;
    vec3 pb = p-vec3(-1,0,0);

    // pb.xy*=Rot(sin(iTime)*.2);
    ph.xy*=Rot(sin(.94));

    ph.y = Parabula(ph);
    ph.x+=sin(ph.z);
    float head=Ball(ph,1.2);

    //BODY
    float scale= mix(.8,1., smoothstep(1.,-1.,pb.x));
    pb.xy*=scale*.7;
    float body = Capsule(pb,vec3(-1.7,0,0),vec3(0,0,0),vec2(.13,.4));

    float wings = Wing(p-vec3(0.,0.,-1.));
    //TAIL
    vec3 pt = p -vec3(-.3,.0,0.);
    // pt.xy*=Rot(sin(iTime)*.2);

    float tail =Tail(pt-vec3(-2.,0.,0.));
    //ADD ALL SHAPE1
    float b=smin(head,body,.9);
     b=smin(b,wings,.1);
     b=smin(b,tail,.1);


    return b;
    // return head;
    // return wings;
}


// BUILD *************************************************************************************
float GetDist(vec3 p){

    // p+=vec3(-2.,0.,0);
    vec3 swim =p-vec3(1.,0.,0.);
    swim.y-=sin(swim.x*1.3+iTime)*(pow(swim.x*.7-.6,2.))*.09;
    // MAKE THE BODY
    float d=Body(swim);
    // MAKE THE TAIL
    // float tail =Tail(p-vec3(-2.,0.,0));
    // MAKE THE WINGS
    // ADD ON EACHOTHER
    // float d = smin(body,tail,.2);

    // TEXTURE DISPLACEMENT
    return d;
}




// RAY MARCHING FUNCTION *************************************************************************************
float RayMarch(vec3 ro,vec3 rd ){
    float d0 = 0.;
    for(int i=0;i<MAX_STEPS;i++){
        vec3 p = ro + rd * d0;
        float dS = GetDist(p);
        d0+=dS;
        if(d0>MAX_DIST || abs(dS)<SURF_DIST) break;

    }
    return d0;
    }



// DISPLACE LIGHTING  *************************************************************************************
vec3 GetNormal(vec3 p){
    float d = GetDist(p);
    vec2 e =vec2(0.01,0.);
    vec3 n = d - vec3(GetDist(p-e.xyy),
    GetDist(p-e.yxy),
    GetDist(p-e.yyx)
    );
    return normalize(n);

}


// CONTROLLE *************************************************************************************
vec3 GetRayDir(vec2 uv, vec3 p, vec3 l, float z) {
    vec3 
        f = normalize(l-p),
        r = normalize(cross(vec3(0,1,0), f)),
        u = cross(f,r),
        c = f*z,
        i = c + uv.x*r + uv.y*u;
    return normalize(i);
}


void mainImage( out vec4 fragColor, in vec2 fragCoord )
{
    // Normalized pixel coordinates (from 0 to 1)
    vec2 uv = fragCoord/iResolution.xy;

    // Time varying pixel color
    vec3 col = 0.5 + 0.5*cos(iTime+uv.xyx+vec3(0,2,4));
    uv = uv-.5 ;
    uv.x*=iResolution.x/iResolution.y;
    col = vec3(.0);

    vec2 m = iMouse.xy/iResolution.xy;
    m-=.5;

    m = m/(uv.xy+5.);


    // CREATE CAMERA
    vec3 ro = vec3(0., -8.,-6.);
    ro.yz *= Rot(-m.y*PI/6.+1.)*.8;
    ro.xz *= Rot(-m.x*TAU/4.);
    vec3 rd = GetRayDir(uv, ro, vec3(0,0.,0), 1.);

    float d = RayMarch(ro,rd);

    if(d<MAX_DIST) {
        vec3 p = ro + rd * d;
        vec3 n = GetNormal(p);
        vec3 r = reflect(rd, n);

        float dif = dot(n, normalize(vec3(1,2,3)))*.5+.5;
        col = vec3(dif);
        col=clamp(col,.1,1.);
        col*=vec3(0.0196, 0.0824, 0.1725);
    }else{
        col=vec3(0.0196, 0.0824, 0.2);
    }

    col = pow(col, vec3(.4545));	
    fragColor =vec4(vec3(col),.0);
}
